import "fmt"

type List[T any] []T

func generate(numRows int) List[List[int]] {
	if numRows == 0 {
		return List[List[int]]{}
	}

	result := make(List[List[int]], numRows)
	result[0] = List[int]{1}

	for i := 1; i < numRows; i++ {
		row := make(List[int], i+1)
		row[0] = 1
		row[i] = 1
		for j := 1; j < i; j++ {
			row[j] = result[i-1][j-1] + result[i-1][j]
		}
		result[i] = row
	}

	return result
}

func main() {
	fmt.Println(generate(5))
}

